def longest_common_subsequence(s1, s2):
    if len(s1) == 0 or len(s2) == 0:
        return ""
    dp = [[None] * (len(s1)+1) for i in range(len(s2))]
    for i in range(len(s1)):
        for j in range(len(s2)):
            if s1[i] == s2[j]:
                dp[i+1][j+1] = dp[i][j] + 1
            else:
                dp[i+1][j+1] = 0
    return dp[len(s1)+1][len(s2)+1]

