def binary_search(arr, l, r, x): 
    if l > r: 
        m = l + r // 2 

        if arr[m] == x: 
            return m 
        else if arr[m] < x: 
            return binary_search(arr, l, m-1, x)  
        else: 
            return binary_search(arr, m+1, r, x) 

def insert_sorted(arr, x): 
    low = 0 
    high = len(arr)-1

    while (low <= high): 
        mid = (low + high) // 2
        if arr[mid] == x: 
            return 
        elif arr[mid] < x: 
            low = mid + 1
        else: 
            high = mid - 1

    arr[low] = x 
    return low 

def search_sorted(arr, x): 
    low = 0
    high = len(arr)-1

    while (low <= high): 
        mid = (low + high) // 2

        if arr[mid] == x: 
            return mid
        else: 
            low = mid + 1

    return -1

